function normalizeEntry(raw){const e={questionUuid:raw.questionUuid,status:raw.status||"DRAFT",stemText:raw.stemText||"",stemDraft:raw.stemDraft||raw.stemText||"",stemConfirmed:Boolean(raw.stemConfirmed),mainTags:Array.isArray(raw.mainTags)?raw.mainTags:[],secondaryTags:Array.isArray(raw.secondaryTags)?raw.secondaryTags:[],secondaryTagsDraft:raw.secondaryTagsDraft||"",difficulty:raw.difficulty!=null?raw.difficulty:null,answerCount:Number(raw.answerCount||0),answerDraft:raw.answerDraft||"",answersLocal:Array.isArray(raw.answersLocal)?raw.answersLocal:[],answersServerData:Array.isArray(raw.answersServerData)?raw.answersServerData:[],answerViewIndex:Number.isInteger(raw.answerViewIndex)?raw.answerViewIndex:0,lastOcrTaskUuid:raw.lastOcrTaskUuid||"",lastOcrStatus:raw.lastOcrStatus||"",lastAnswerOcrTaskUuid:raw.lastAnswerOcrTaskUuid||"",lastAnswerOcrStatus:raw.lastAnswerOcrStatus||"",stemImageBase64:raw.stemImageBase64||"",inlineImages:raw.inlineImages&&typeof raw.inlineImages==="object"?raw.inlineImages:{},answerImages:raw.answerImages&&typeof raw.answerImages==="object"?raw.answerImages:{},assetsLoaded:Boolean(raw.assetsLoaded),updatedAt:Number(raw.updatedAt||Date.now())};ensureMainTags(e);ensureAnswerViewIndex(e);if(!e.secondaryTagsDraft)e.secondaryTagsDraft=(e.secondaryTags||[]).join(" ");return e}
