function loadWorkspace(){if(!state.username)return;state.entries.clear();state.ocrTasks.clear();state.selectedQuestionUuid="";const raw=localStorage.getItem(storageKey());if(!raw)return;try{const o=JSON.parse(raw);for(const it of o.entries||[]){const e=normalizeEntry(it);state.entries.set(e.questionUuid,e)}for(const t of o.ocrTasks||[])state.ocrTasks.set(t.taskUuid,t);if(o.selectedQuestionUuid&&state.entries.has(o.selectedQuestionUuid))state.selectedQuestionUuid=o.selectedQuestionUuid;if(o.activeTab)state.activeTab=o.activeTab;if(o.bankSelectedUuid&&state.entries.has(o.bankSelectedUuid))state.bankSelectedUuid=o.bankSelectedUuid}catch{}}
