function difficultyLevel(p){if(p==null||p==="")return{label:"-",cls:"",range:""};const v=Number(p);if(!Number.isFinite(v))return{label:"-",cls:"",range:""};if(v>=0.70)return{label:"简单",cls:"d-easy",range:"P≥0.70"};if(v>=0.50)return{label:"中等偏易",cls:"d-medium-easy",range:"0.50≤P<0.70"};if(v>=0.30)return{label:"中等",cls:"d-medium",range:"0.30≤P<0.50"};if(v>=0.15)return{label:"较难",cls:"d-hard",range:"0.15≤P<0.30"};return{label:"极难",cls:"d-very-hard",range:"P<0.15"}}
