function assignInlineBlankIds(blocks){let maxId=0;for(const b of blocks){if(b.type==="blanks")for(const it of(b.items||[]))maxId=Math.max(maxId,Number(it.id)||0);if(b.inlineBlanks)for(const it of b.inlineBlanks)maxId=Math.max(maxId,Number(it.id)||0)}for(const b of blocks){if(b.type!=="p")continue;const text=b.text||"";const ms=text.match(/____/g);if(!ms||!ms.length){delete b.inlineBlanks;continue}if(b.inlineBlanks&&b.inlineBlanks.length===ms.length)continue;b.inlineBlanks=[];for(let i=0;i<ms.length;i++){maxId++;b.inlineBlanks.push({id:String(maxId)})}}}
