function renderStemEditor(entry){const editor=$("stem-editor");if(!editor)return;if(editor.contains(document.activeElement)&&document.activeElement.tagName!=="BUTTON")return;editor.innerHTML="";if(!entry){editor.innerHTML='<div class="stem-editor-empty">\u8bf7\u5148\u9009\u62e9\u4efb\u52a1</div>';return}const source=entry.stemDraft||entry.stemText||"";const blocks=xmlToBlocks(source);for(const b of blocks){editor.appendChild(createBlockEl(b,entry))}if(blocks.length===1&&blocks[0].type==="p"&&!blocks[0].text.trim()){const hint=editor.querySelector(".block-text-input");if(hint)hint.placeholder="\u7b49\u5f85 OCR \u7ed3\u679c\uff0c\u6216\u624b\u52a8\u8f93\u5165\u9898\u5e72\u6587\u5b57"}}
function collectBlocksFromEditor(){const editor=$("stem-editor");if(!editor)return[];const blocks=[];for(const el of editor.querySelectorAll(".stem-block")){const type=el.dataset.type;if(type==="p"){const inp=el.querySelector(".block-text-input");blocks.push({type:"p",text:inp?inp.value:""})}else if(type==="choices"){const items=[];for(const row of el.querySelectorAll(".choice-edit-row")){const inp=row.querySelector(".choice-text-input");const preview=row.querySelector(".choice-image-preview");items.push({key:inp?.dataset.key||"",text:inp?.value||"",imageRef:preview?.dataset.ref||""})}const lbl=el.querySelector(".block-type-label");const mode=lbl&&lbl.textContent.includes("\u591a\u9009")?"multi":"single";blocks.push({type:"choices",mode,items})}else if(type==="image"){blocks.push({type:"image",ref:el.dataset.ref||"stem-local"})}else if(type==="blanks"){const items=[];for(const chip of el.querySelectorAll(".blank-edit-chip")){const id=chip.textContent.replace(/^\u7a7a/,"");items.push({id})}blocks.push({type:"blanks",items})}else if(type==="answer-area"){const inp=el.querySelector(".answer-area-lines-input");blocks.push({type:"answer-area",lines:Number(inp?.value||4)})}}assignInlineBlankIds(blocks);return blocks}
function editorChanged(){const e=selectedEntry();if(!e)return;const blocks=collectBlocksFromEditor();const xml=blocksToXml(blocks);e.stemDraft=xml;e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderLatex("stem-preview",xml,"\u9898\u5e72 LaTeX \u9884\u89c8\u533a\u57df",{imageResolver:ref=>resolveStemImage(e,ref)})}
function addStemBlock(type){const e=selectedEntry();if(!e)return;const blocks=collectBlocksFromEditor();if(type==="p"){blocks.push({type:"p",text:""})}else if(type==="choices"){blocks.push({type:"choices",mode:"single",items:[{key:"A",text:""},{key:"B",text:""},{key:"C",text:""},{key:"D",text:""}]})}else if(type==="blanks"){let mx=0;for(const b of blocks){if(b.type==="blanks")for(const it of(b.items||[]))mx=Math.max(mx,Number(it.id)||0);if(b.inlineBlanks)for(const it of b.inlineBlanks)mx=Math.max(mx,Number(it.id)||0)}blocks.push({type:"blanks",items:[{id:String(mx+1)}]})}else if(type==="answer-area"){blocks.push({type:"answer-area",lines:4})}else if(type==="image"){blocks.push({type:"image",ref:"stem-local"})}const xml=blocksToXml(blocks);e.stemDraft=xml;e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderStemEditor(e);renderLatex("stem-preview",xml,"\u9898\u5e72 LaTeX \u9884\u89c8\u533a\u57df",{imageResolver:ref=>resolveStemImage(e,ref)})}
function renderBankDifficulty(e){const badge=$("bank-difficulty-badge");const slider=$("bank-difficulty-slider");const valSpan=$("bank-difficulty-value");if(e.difficulty!=null&&e.difficulty!==""){const v=Number(e.difficulty);const dl=difficultyLevel(v);badge.textContent=dl.label;badge.className=`difficulty-badge ${dl.cls}`;slider.value=String(Math.round(v*100));slider.classList.remove("unset");valSpan.textContent=v.toFixed(2)}else{badge.textContent="未设置";badge.className="difficulty-badge d-unset";slider.value="50";slider.classList.add("unset");valSpan.textContent="-"}}
function renderBankStemEditor(entry){const editor=$("bank-stem-structured-editor");if(!editor)return;if(editor.contains(document.activeElement)&&document.activeElement.tagName!=="BUTTON")return;editor.innerHTML="";if(!entry){editor.innerHTML='<div class="stem-editor-empty">请先选择题目</div>';return}const source=entry.stemDraft||entry.stemText||"";const blocks=xmlToBlocks(source);for(const b of blocks){editor.appendChild(createBlockEl(b,entry))}}
function collectBankBlocksFromEditor(){const editor=$("bank-stem-structured-editor");if(!editor)return[];const blocks=[];for(const el of editor.querySelectorAll(".stem-block")){const type=el.dataset.type;if(type==="p"){const inp=el.querySelector(".block-text-input");blocks.push({type:"p",text:inp?inp.value:""})}else if(type==="choices"){const items=[];for(const row of el.querySelectorAll(".choice-edit-row")){const inp=row.querySelector(".choice-text-input");const preview=row.querySelector(".choice-image-preview");items.push({key:inp?.dataset.key||"",text:inp?.value||"",imageRef:preview?.dataset.ref||""})}const lbl=el.querySelector(".block-type-label");const mode=lbl&&lbl.textContent.includes("\u591a\u9009")?"multi":"single";blocks.push({type:"choices",mode,items})}else if(type==="image"){blocks.push({type:"image",ref:el.dataset.ref||"stem-local"})}else if(type==="blanks"){const items=[];for(const chip of el.querySelectorAll(".blank-edit-chip")){const id=chip.textContent.replace(/^\u7a7a/,"");items.push({id})}blocks.push({type:"blanks",items})}else if(type==="answer-area"){const inp=el.querySelector(".answer-area-lines-input");blocks.push({type:"answer-area",lines:Number(inp?.value||4)})}}assignInlineBlankIds(blocks);return blocks}
function bankEditorChanged(){const e=bankSelectedEntry();if(!e)return;const blocks=collectBankBlocksFromEditor();const xml=blocksToXml(blocks);e.stemDraft=xml;e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderLatex("bank-stem-edit-preview",xml,"预览区",{imageResolver:ref=>resolveStemImage(e,ref)})}
function createAnswerBlockEl(block,entry){
  const wrap=document.createElement("div");
  wrap.className="stem-block stem-"+block.type+"-block";
  wrap.dataset.type=block.type;
  if(block.type==="image") wrap.dataset.ref=block.ref||"img-1";
  wrap.draggable=true;
  const handle=document.createElement("div");
  handle.className="block-handle";
  const dragH=document.createElement("span");
  dragH.className="block-drag-handle";
  dragH.textContent="\u2630";
  dragH.title="\u62d6\u62fd\u6392\u5e8f";
  const label=document.createElement("span");
  label.className="block-type-label";
  const rb=document.createElement("button");
  rb.className="block-remove-btn";
  rb.textContent="\u00d7";
  rb.title="\u5220\u9664\u6b64\u6a21\u5757";
  handle.appendChild(dragH);
  handle.appendChild(label);
  handle.appendChild(rb);
  if(block.type==="p"){
    label.textContent="\u6bb5\u843d";
    wrap.appendChild(handle);
    const ta=document.createElement("textarea");
    ta.className="block-text-input";
    ta.value=block.text||"";
    ta.placeholder="\u8f93\u5165\u6bb5\u843d\u6587\u672c\uff08\u652f\u6301 LaTeX\uff0c\u5982 $x^2+1$\uff09";
    ta.rows=1;
    const ar=()=>{ta.style.height="auto";ta.style.height=Math.max(40,ta.scrollHeight)+"px"};
    ta.addEventListener("input",ar);
    wrap.appendChild(ta);
    requestAnimationFrame(ar);
  }else if(block.type==="image"){
    label.textContent="\u914d\u56fe";
    wrap.appendChild(handle);
    const info=document.createElement("div");
    info.className="block-image-info";
    const ref=block.ref||"img-1";
    const src=imageDataUrl(resolveAnswerImage(entry,ref));
    if(src){
      const img=document.createElement("img");
      img.src=src;
      img.className="block-image-thumb";
      info.appendChild(img);
    }else{
      info.textContent="[\u914d\u56fe\u5f15\u7528: "+ref+"]";
    }
    wrap.appendChild(info);
  }
  return wrap;
}
function renderAnswerStructuredEditor(editorId,blocks,entry){const editor=$(editorId);if(!editor)return;editor.innerHTML="";for(const b of blocks){editor.appendChild(createAnswerBlockEl(b,entry))}if(blocks.length===1&&blocks[0].type==="p"&&!blocks[0].text.trim()){const hint=editor.querySelector(".block-text-input");if(hint)hint.placeholder="\u8f93\u5165\u7b54\u6848\u6587\u672c\uff08\u652f\u6301 LaTeX\uff09"}}
function collectAnswerBlocksFromEditor(editorId){
  const editor=$(editorId);
  if(!editor) return [];
  const blocks=[];
  for(const el of editor.querySelectorAll(".stem-block")){
    const type=el.dataset.type;
    if(type==="p"){
      const inp=el.querySelector(".block-text-input");
      blocks.push({type:"p",text:inp?inp.value:""});
    }else if(type==="image"){
      blocks.push({type:"image",ref:el.dataset.ref||"fig-1"});
    }
  }
  assignInlineBlankIds(blocks);
  return blocks;
}
function answerEditorChanged(editorId,previewId,entry){const blocks=collectAnswerBlocksFromEditor(editorId);const xml=blocksToAnswerXml(blocks);renderAnswerLatex(previewId,xml,"\u7b54\u6848\u9884\u89c8",entry)}
function addAnswerBlock(editorId,previewId,type,entry){
  const blocks=collectAnswerBlocksFromEditor(editorId);
  if(type==="p"){
    blocks.push({type:"p",text:""});
  }else if(type==="image"){
    const ref=nextAnswerRefForBlocks(blocks,entry);
    blocks.push({type:"image",ref});
  }
  const xml=blocksToAnswerXml(blocks);
  renderAnswerStructuredEditor(editorId,answerXmlToBlocks(xml),entry);
  renderAnswerLatex(previewId,xml,"\u7b54\u6848\u9884\u89c8",entry);
}
function renderAnswerLatex(elOrId,xml,placeholder,entry){const node=typeof elOrId==="string"?$(elOrId):elOrId;if(!node)return;const c=String(xml||"").trim();if(!c){node.innerHTML="";node.textContent=placeholder;return}const doc=parseAnswerXmlDoc(c);if(!doc){renderLatexNode(node,c,placeholder,{imageResolver:ref=>resolveAnswerImage(entry,ref)});return}node.innerHTML="";const imageResolver=ref=>resolveAnswerImage(entry,ref);function processNode(xmlNode,parentEl){if(xmlNode.nodeType===Node.TEXT_NODE){parentEl.appendChild(document.createTextNode(xmlNode.nodeValue||""));return}if(xmlNode.nodeType!==Node.ELEMENT_NODE)return;const tag=String(xmlNode.tagName||"").toLowerCase();if(tag==="answer"){Array.from(xmlNode.childNodes).forEach(n=>processNode(n,parentEl));return}if(tag==="p"){const p=document.createElement("p");p.className="stem-p";Array.from(xmlNode.childNodes).forEach(n=>processNode(n,p));parentEl.appendChild(p);return}if(tag==="image"){const ref=(xmlNode.getAttribute("ref")||"").trim();const src=imageDataUrl(imageResolver(ref));if(src){const img=document.createElement("img");img.className="stem-image";img.src=src;img.alt=ref?"image-"+ref:"answer-image";parentEl.appendChild(img)}else{const note=document.createElement("span");note.className="empty-note";note.textContent=ref?"[\u914d\u56fe: "+ref+"]":"[\u914d\u56fe]";parentEl.appendChild(note)}return}if(tag==="blank"){const span=document.createElement("span");span.className="blank-item";span.textContent=" ";const id=(xmlNode.getAttribute("id")||"").trim();if(id)span.title="blank-"+id;parentEl.appendChild(span);return}Array.from(xmlNode.childNodes).forEach(n=>processNode(n,parentEl))}processNode(doc.documentElement,node);if(typeof window.renderMathInElement==="function")try{window.renderMathInElement(node,{delimiters:KATEX_DELIMITERS,throwOnError:false,strict:"ignore"})}catch{}}
function addBankStemBlock(type){const e=bankSelectedEntry();if(!e)return;const blocks=collectBankBlocksFromEditor();if(type==="p"){blocks.push({type:"p",text:""})}else if(type==="choices"){blocks.push({type:"choices",mode:"single",items:[{key:"A",text:""},{key:"B",text:""},{key:"C",text:""},{key:"D",text:""}]})}else if(type==="blanks"){let mx=0;for(const b of blocks){if(b.type==="blanks")for(const it of(b.items||[]))mx=Math.max(mx,Number(it.id)||0);if(b.inlineBlanks)for(const it of b.inlineBlanks)mx=Math.max(mx,Number(it.id)||0)}blocks.push({type:"blanks",items:[{id:String(mx+1)}]})}else if(type==="answer-area"){blocks.push({type:"answer-area",lines:4})}else if(type==="image"){blocks.push({type:"image",ref:"stem-local"})}const xml=blocksToXml(blocks);e.stemDraft=xml;e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderBankStemEditor(e);renderLatex("bank-stem-edit-preview",xml,"预览区",{imageResolver:ref=>resolveStemImage(e,ref)})}
function renderBankAiStatus(e){const box=$("bank-ai-status");if(!box)return;if(state.bankAiPending.has(e.questionUuid)){box.classList.remove("hidden","ai-success","ai-error");box.classList.add("ai-loading");box.textContent="AI 分析中，请稍候…";$("bank-ai-btn").classList.add("loading");$("bank-ai-btn").disabled=true}else if(state.bankAiLastResult&&state.bankAiLastResult.questionUuid===e.questionUuid){const r=state.bankAiLastResult;box.classList.remove("hidden","ai-loading");$("bank-ai-btn").classList.remove("loading");$("bank-ai-btn").disabled=false;if(r.success){box.classList.remove("ai-error");box.classList.add("ai-success");box.innerHTML=`<strong>AI 分析完成</strong><br/>推荐标签: ${(r.suggestedTags||[]).join(", ")||"-"}<br/>推荐难度: ${r.suggestedDifficulty!=null?Number(r.suggestedDifficulty).toFixed(2):"-"}<br/><small>${r.reasoning||""}</small><div class="ai-apply-actions"><button class="btn btn-primary btn-sm ai-apply-btn" data-action="apply">应用推荐</button><button class="btn btn-success btn-sm ai-apply-complete-btn" data-action="apply-complete">应用推荐并完成录入</button></div>`;box.querySelector(".ai-apply-btn").addEventListener("click",()=>applyAiRecommendation(e.questionUuid,r,false));box.querySelector(".ai-apply-complete-btn").addEventListener("click",()=>applyAiRecommendation(e.questionUuid,r,true))}else{box.classList.remove("ai-success");box.classList.add("ai-error");box.textContent=`AI 分析失败: ${r.errorMessage||"未知错误"}`}}else{box.classList.add("hidden");box.classList.remove("ai-loading","ai-success","ai-error");$("bank-ai-btn").classList.remove("loading");$("bank-ai-btn").disabled=false}}
async function bankUpdateTags(questionUuid,tags){await api(`/api/questions/${questionUuid}/tags`,"PUT",{tags});const e=state.entries.get(questionUuid);if(e){e.secondaryTags=[...tags];e.secondaryTagsDraft=tags.join(" ");e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace();renderBankDetail()}}
function renderEntryAiStatus(e){const box=$("entry-ai-status");const aiBtn=$("entry-ai-btn");if(!box)return;if(!e){box.classList.add("hidden");box.classList.remove("ai-loading","ai-success","ai-error");if(aiBtn){aiBtn.classList.remove("loading");aiBtn.disabled=false}return}if(state.entryAiPending.has(e.questionUuid)){box.classList.remove("hidden","ai-success","ai-error");box.classList.add("ai-loading");box.textContent="AI 分析中，请稍候…";if(aiBtn){aiBtn.classList.add("loading");aiBtn.disabled=true}}else if(state.entryAiLastResult&&state.entryAiLastResult.questionUuid===e.questionUuid){const r=state.entryAiLastResult;box.classList.remove("hidden","ai-loading");if(aiBtn){aiBtn.classList.remove("loading");aiBtn.disabled=false}if(r.success){box.classList.remove("ai-error");box.classList.add("ai-success");box.innerHTML=`<strong>AI 分析完成</strong><br/>推荐标签: ${(r.suggestedTags||[]).join(", ")||"-"}<br/>推荐难度: ${r.suggestedDifficulty!=null?Number(r.suggestedDifficulty).toFixed(2):"-"}<br/><small>${r.reasoning||""}</small><div class="ai-apply-actions"><button class="btn btn-primary btn-sm ai-apply-btn" data-action="apply">应用推荐</button><button class="btn btn-success btn-sm ai-apply-complete-btn" data-action="apply-complete">应用推荐并完成录入</button></div>`;box.querySelector(".ai-apply-btn").addEventListener("click",()=>applyAiRecommendation(e.questionUuid,r,false));box.querySelector(".ai-apply-complete-btn").addEventListener("click",()=>applyAiRecommendation(e.questionUuid,r,true))}else{box.classList.remove("ai-success");box.classList.add("ai-error");box.textContent=`AI 分析失败: ${r.errorMessage||"未知错误"}`}}else{box.classList.add("hidden");box.classList.remove("ai-loading","ai-success","ai-error");if(aiBtn){aiBtn.classList.remove("loading");aiBtn.disabled=false}}}
async function applyAiRecommendation(questionUuid,r,andComplete){try{const taskUuid=r.taskUuid;if(!taskUuid){log("无法应用: 缺少 taskUuid");return}const body={tags:r.suggestedTags||[],difficulty:r.suggestedDifficulty!=null?Number(r.suggestedDifficulty):null};await api(`/api/questions/${questionUuid}/ai-tasks/${taskUuid}/apply`,"PUT",body);const e=state.entries.get(questionUuid);if(e){if(Array.isArray(r.suggestedTags)&&r.suggestedTags.length){e.secondaryTags=[...new Set([...(e.secondaryTags||[]),...r.suggestedTags])];e.secondaryTagsDraft=e.secondaryTags.join(" ")}if(r.suggestedDifficulty!=null){e.difficulty=Number(r.suggestedDifficulty);try{await api(`/api/questions/${questionUuid}/difficulty`,"PUT",{difficulty:Number(r.suggestedDifficulty)})}catch(_){log("难度独立保存失败（已通过apply端点发送）")}}e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace()}log(`AI推荐已应用: ${questionUuid}`);if(andComplete){const cr=await api(`/api/questions/${questionUuid}/complete`,"POST");const e2=state.entries.get(questionUuid);if(e2){e2.status=cr.data&&cr.data.status?cr.data.status:"READY";e2.updatedAt=Date.now();state.entries.set(questionUuid,e2);saveWorkspace()}log(`题目已完成: ${questionUuid}`)}state.bankAiLastResult=null;state.entryAiLastResult=null;renderAll()}catch(err){log(`应用AI推荐失败: ${errMsg(err)}`)}}
async function bankUpdateDifficulty(questionUuid,value){await api(`/api/questions/${questionUuid}/difficulty`,"PUT",{difficulty:value});const e=state.entries.get(questionUuid);if(e){e.difficulty=value;e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace();renderBankDetail();renderBankList()}}
async function bankRequestAi(questionUuid){try{state.bankAiPending.add(questionUuid);state.bankAiLastResult=null;renderBankAiStatus(bankSelectedEntry());const aiRes=await api(`/api/questions/${questionUuid}/ai-analysis`,"POST");const tUuid=aiRes.data&&aiRes.data.taskUuid;if(tUuid){state.bankAiLastResult={questionUuid,taskUuid:tUuid,pending:true}}log(`AI分析已发起: ${questionUuid}`)}catch(err){state.bankAiPending.delete(questionUuid);renderBankAiStatus(bankSelectedEntry());log(`AI分析请求失败: ${errMsg(err)}`)}}
async function bankDeleteAnswer(questionUuid,answerUuid){await api(`/api/questions/${questionUuid}/answers/${answerUuid}`,"DELETE");const e=state.entries.get(questionUuid);if(e){const idx=(e.answersServerData||[]).findIndex(a=>a.answerUuid===answerUuid);if(idx>=0){e.answersServerData.splice(idx,1);e.answersLocal.splice(idx,1);e.answerCount=Math.max(0,(e.answerCount||1)-1)}state.bankAnswerIdx=Math.max(0,Math.min(state.bankAnswerIdx,e.answersLocal.length-1));e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace();renderBankDetail();renderBankList();log(`答案已删除: ${questionUuid}`)}};
async function bankUpdateAnswer(questionUuid,answerUuid,latexText,answerInlineImages){const body={latexText};if(answerInlineImages&&Object.keys(answerInlineImages).length)body.inlineImages=answerInlineImages;await api(`/api/questions/${questionUuid}/answers/${answerUuid}`,"PUT",body);const e=state.entries.get(questionUuid);if(e){const idx=(e.answersServerData||[]).findIndex(a=>a.answerUuid===answerUuid);if(idx>=0){e.answersServerData[idx].latexText=latexText;e.answersLocal[idx]=latexText}e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace();renderBankDetail();log(`答案已更新: ${questionUuid}`)}};
async function bankAddAnswer(questionUuid,latexText,answerInlineImages){const body={latexText};if(answerInlineImages&&Object.keys(answerInlineImages).length)body.inlineImages=answerInlineImages;const r=await api(`/api/questions/${questionUuid}/answers`,"POST",body);const newUuid=(r.data&&r.data.answerUuid)||r.data?.answer?.answerUuid||"";const e=state.entries.get(questionUuid);if(e){e.answersLocal=[...(e.answersLocal||[]),latexText];e.answersServerData=[...(e.answersServerData||[]),{answerUuid:newUuid,latexText}];e.answerCount=e.answersLocal.length;state.bankAnswerIdx=e.answersLocal.length-1;e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace();renderBankDetail();renderBankList();log(`答案已新增: ${questionUuid}`)}try{await syncQuestions()}catch(_){}};;
async function bankSaveStem(questionUuid,text){const stemXml=toStemXmlPayload(text);const e=state.entries.get(questionUuid);const inlineImages={};for(const [ref,base64] of Object.entries(e?.inlineImages||{})){if(base64&&typeof base64==="string")inlineImages[ref]={imageData:base64,mimeType:"image/png"}}await api(`/api/questions/${questionUuid}/stem`,"PUT",{stemXml,inlineImages});if(e){e.stemText=stemXml;e.stemDraft=toEditorStemText(stemXml);e.assetsLoaded=true;e.updatedAt=Date.now();state.entries.set(questionUuid,e);saveWorkspace();renderBankDetail();renderBankList();log(`题干已更新: ${questionUuid}`)}}
function handleAiResult(msg){const p=msg.payload||{};const qid=p.questionUuid;if(!qid)return;state.bankAiPending.delete(qid);state.entryAiPending.delete(qid);if(msg.event==="ai.analysis.succeeded"){log(`AI分析完成: ${qid}`);const result={questionUuid:qid,taskUuid:p.taskUuid||"",success:true,suggestedTags:p.suggestedTags||[],suggestedDifficulty:p.suggestedDifficulty,reasoning:p.reasoning||""};state.bankAiLastResult=result;state.entryAiLastResult=result;renderAll()}else if(msg.event==="ai.analysis.failed"){log(`AI分析失败: ${qid} — ${p.errorMessage||"未知错误"}`);const result={questionUuid:qid,taskUuid:p.taskUuid||"",success:false,errorMessage:p.errorMessage||"未知错误"};state.bankAiLastResult=result;state.entryAiLastResult=result;renderAll()}}
async function api(path,method,body){return window.qforge.api.request(path,method,state.token,body)}
async function fetchAssets(questionUuid){const e=state.entries.get(questionUuid);if(!e||e.assetsLoaded)return;try{const r=await api(`/api/questions/${questionUuid}/assets`,"GET");const stemImgs={};const ansImgs={};for(const a of (r.data||[])){if(a.refKey&&a.imageData){if(/^a[0-9a-f]{8}-img-/.test(a.refKey))ansImgs[a.refKey]=a.imageData;else stemImgs[a.refKey]=a.imageData}}e.inlineImages=Object.assign({},e.inlineImages,stemImgs);e.answerImages=Object.assign({},e.answerImages,ansImgs);e.assetsLoaded=true;state.entries.set(questionUuid,e);saveWorkspace();renderAll()}catch(err){log(`图片加载失败: ${errMsg(err)}`)}}
async function loadTags(){try{const r=await api("/api/tags","GET");state.tagCatalog=normalizeCatalog(r.data||{});for(const e of state.entries.values())ensureMainTags(e)}catch(e){log(`标签字典加载失败: ${errMsg(e)}`)}}
function wsUrl(){const root=state.config.wsBaseUrl.endsWith("/")?state.config.wsBaseUrl.slice(0,-1):state.config.wsBaseUrl;return `${root}/ws/questions?user=${encodeURIComponent(state.username)}&token=${encodeURIComponent(state.token)}`}
let ocrRuntime=null
function ensureOcrRuntime(){if(ocrRuntime)return ocrRuntime;if(!(window.QForgeOcrRuntime&&typeof window.QForgeOcrRuntime.createOcrRuntime==="function"))throw new Error("QForgeOcrRuntime not loaded");ocrRuntime=window.QForgeOcrRuntime.createOcrRuntime({state,log,handleAiResult,toAnswerXmlPayload,saveWorkspace,renderAll,fetchAssets,wsUrl});return ocrRuntime}
function upsertWs(msg){return ensureOcrRuntime().upsertWs(msg)}
function connectWs(){return ensureOcrRuntime().connectWs()}
async function toBase64(file){return await new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>{const raw=String(r.result||"");const idx=raw.indexOf(",");res(idx>=0?raw.slice(idx+1):raw)};r.onerror=()=>rej(new Error("读取图片失败"));r.readAsDataURL(file)})}
function createEntry(q){const stem=q.stemText||"";const ans=Array.isArray(q.answers)?q.answers:[];return normalizeEntry({questionUuid:q.questionUuid,status:q.status,stemText:stem,stemDraft:toEditorStemText(stem),stemConfirmed:Boolean(stem&&stem.trim()),mainTags:q.mainTags,secondaryTags:q.secondaryTags,difficulty:q.difficulty!=null?q.difficulty:null,answerCount:Number(q.answerCount||ans.length||0),answerDraft:"",answersLocal:ans.map(a=>a.latexText).filter(Boolean),answersServerData:ans.filter(a=>a.latexText).map(a=>({answerUuid:a.answerUuid||"",latexText:a.latexText||""})),answerViewIndex:0,lastOcrTaskUuid:"",lastOcrStatus:"",lastAnswerOcrTaskUuid:"",lastAnswerOcrStatus:"",stemImageBase64:"",inlineImages:{},answerImages:{},assetsLoaded:false,updatedAt:Number(q.updatedAt?new Date(q.updatedAt).getTime():Date.now())})}
async function createTask(){const r=await api("/api/questions","POST",{});const e=createEntry(r.data);state.entries.set(e.questionUuid,e);state.selectedQuestionUuid=e.questionUuid;saveWorkspace();renderAll();log(`新建任务: ${e.questionUuid}`)}
async function createBatch(){const n=Number($("batch-count").value||0);if(!Number.isFinite(n)||n<2||n>20)throw new Error("批量数量范围: 2-20");for(let i=0;i<n;i+=1)await createTask();log(`批量创建完成: ${n} 个任务`)}
async function submitOcrForEntry(e,imageBase64,bizType){const r=await api(`/api/questions/${e.questionUuid}/ocr-tasks`,`POST`,{imageBase64,bizType});const t={taskUuid:r.data.taskUuid,questionUuid:e.questionUuid,bizType,status:r.data.status||"PENDING",recognizedText:"",errorMessage:"",updatedAt:Date.now()};state.ocrTasks.set(t.taskUuid,t);if(bizType==="ANSWER_CONTENT"){e.lastAnswerOcrTaskUuid=t.taskUuid;e.lastAnswerOcrStatus=t.status}else{e.lastOcrTaskUuid=t.taskUuid;e.lastOcrStatus=t.status}e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderAll();return t.taskUuid}
async function submitStemOcr(){const e=selectedEntry();if(!e)throw new Error("请先选择任务");const f=$("ocr-image-input").files?.[0];if(!f)throw new Error("请先选择图片");const id=await submitOcrForEntry(e,await toBase64(f),"QUESTION_STEM");log(`题干OCR任务已提交: ${id}`)}
async function submitAnswerOcr(){const e=selectedEntry();if(!e)throw new Error("请先选择任务");if(stageOf(e)!=="PENDING_ANSWER")throw new Error("当前阶段不可发起答案 OCR");const f=$("answer-ocr-image-input").files?.[0];if(!f)throw new Error("请先选择答案图片");const id=await submitOcrForEntry(e,await toBase64(f),"ANSWER_CONTENT");log(`答案OCR任务已提交: ${id}`)}
function fillLatest(){const e=selectedEntry();const t=selectedTask();if(!e||!t||!t.recognizedText)throw new Error("当前任务没有可用识别结果");e.stemDraft=t.recognizedText;e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderAll();log("已填充OCR结果到题干编辑区")}
function fillLatestAnswer(){const e=selectedEntry();const t=selectedAnswerTask();if(!e||!t||!t.recognizedText)throw new Error("当前任务没有可用答案识别结果");e.answerDraft=toAnswerXmlPayload(t.recognizedText);e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderAll();log("已填充OCR结果到答案编辑区")}
async function confirmStem(){const e=selectedEntry();if(!e)throw new Error("请先选择任务");const confirmedBlocks=collectBlocksFromEditor();const hasContent=confirmedBlocks.some(b=>(b.type==="p"&&b.text.trim())||b.type!=="p");if(!hasContent)throw new Error("题干不能为空");const confirmedText=blocksToXml(confirmedBlocks);ensureMainTags(e);const pendingInput=$("stem-secondary-tags-input").value.trim();if(pendingInput){e.secondaryTags=[...new Set([...(e.secondaryTags||[]),pendingInput])];$("stem-secondary-tags-input").value=""}const secondaryTagsText=(e.secondaryTags||[]).join(" ");const mainTags=(e.mainTags||[]).map(t=>({categoryCode:t.categoryCode,tagCode:t.tagCode}));const stemXml=toStemXmlPayload(confirmedText);const inlineImages={};for(const [ref,base64] of Object.entries(e.inlineImages||{})){if(base64&&typeof base64==="string")inlineImages[ref]={imageData:base64,mimeType:"image/png"}}const r=await api(`/api/questions/${e.questionUuid}/stem`,`PUT`,{stemXml,mainTags,secondaryTagsText,inlineImages});e.status=r.data.status;e.stemText=stemXml;e.stemDraft=toEditorStemText(stemXml);e.stemConfirmed=true;e.secondaryTagsDraft=secondaryTagsText;e.assetsLoaded=true;e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderAll();log(`题干已确认: ${e.questionUuid}`)}
async function addAnswer(){const e=selectedEntry();if(!e)throw new Error("请先选择任务");if(!e.stemConfirmed)throw new Error("请先确认题干");const blocks=collectAnswerBlocksFromEditor("entry-answer-structured-editor");const hasContent=blocks.some(b=>(b.type==="p"&&b.text.trim())||b.type!=="p");if(!hasContent)throw new Error("答案不能为空");const payload=buildAnswerSubmitPayload(e,blocks,null);const answerXml=payload.latexText;const answerInlineImages=payload.inlineImages;const r=await api(`/api/questions/${e.questionUuid}/answers`,"POST",{latexText:answerXml,inlineImages:Object.keys(answerInlineImages).length?answerInlineImages:undefined});const newUuid=(r.data&&r.data.answerUuid)||r.data?.answer?.answerUuid||"";e.status=r.data.status;e.answerCount=(e.answerCount||0)+1;e.answersLocal=[...(e.answersLocal||[]),answerXml];e.answersServerData=[...(e.answersServerData||[]),{answerUuid:newUuid,latexText:answerXml}];e.answerViewIndex=Math.max(0,e.answersLocal.length-1);e.answerDraft="";e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderAll();log(`答案已添加: ${e.questionUuid}`);}
async function completeQ(){const e=selectedEntry();if(!e)throw new Error("请先选择任务");const r=await api(`/api/questions/${e.questionUuid}/complete`,`POST`);e.status=r.data.status;ensureAnswerViewIndex(e);e.updatedAt=Date.now();state.entries.set(e.questionUuid,e);saveWorkspace();renderAll();log(`任务已完成(READY): ${e.questionUuid}`)}
async function delQ(qid){if(!qid)throw new Error("questionUuid is required");await api(`/api/questions/${qid}`,"DELETE");state.entries.delete(qid);state.contextMenuQuestionUuid="";for(const [id,t] of state.ocrTasks.entries())if(t.questionUuid===qid)state.ocrTasks.delete(id);if(state.selectedQuestionUuid===qid){const n=[...state.entries.values()].sort((a,b)=>(b.updatedAt||0)-(a.updatedAt||0))[0];state.selectedQuestionUuid=n?n.questionUuid:""}hideMenu();saveWorkspace();renderAll();log(`已删除未完成题目: ${qid}`)}
async function syncQuestions(){const r=await api("/api/questions","GET");const rows=Array.isArray(r.data)?r.data:[];const old=new Map(state.entries);const merged=new Map();for(const row of rows){const p=old.get(row.questionUuid);const stem=row.stemText||"";const ans=Array.isArray(row.answers)?row.answers:[];const ansText=ans.map(a=>a.latexText).filter(Boolean);const e=normalizeEntry({questionUuid:row.questionUuid,status:row.status||"DRAFT",stemText:stem,stemDraft:p?p.stemDraft||toEditorStemText(stem):toEditorStemText(stem),stemConfirmed:stem.trim().length>0||row.status==="READY",mainTags:row.mainTags,secondaryTags:row.secondaryTags,secondaryTagsDraft:p?p.secondaryTagsDraft:(Array.isArray(row.secondaryTags)?row.secondaryTags.join(" "):""),difficulty:row.difficulty!=null?row.difficulty:(p?p.difficulty:null),answerCount:Number(row.answerCount||ansText.length||0),answerDraft:p?p.answerDraft:"",answersLocal:ansText.length?ansText:(p?p.answersLocal:[]),answersServerData:ans.filter(a=>a.latexText).map(a=>({answerUuid:a.answerUuid||"",latexText:a.latexText||""})),answerViewIndex:p?p.answerViewIndex:0,lastOcrTaskUuid:p?p.lastOcrTaskUuid:"",lastOcrStatus:p?p.lastOcrStatus:"",lastAnswerOcrTaskUuid:p?p.lastAnswerOcrTaskUuid:"",lastAnswerOcrStatus:p?p.lastAnswerOcrStatus:"",stemImageBase64:p?p.stemImageBase64:"",inlineImages:p?p.inlineImages:{},answerImages:p?p.answerImages:{},assetsLoaded:p?p.assetsLoaded:false,updatedAt:Number.isFinite(new Date(row.updatedAt).getTime())?new Date(row.updatedAt).getTime():Date.now()});merged.set(row.questionUuid,e)}state.entries=merged;for(const [id,t] of state.ocrTasks.entries())if(!merged.has(t.questionUuid))state.ocrTasks.delete(id);if(!state.selectedQuestionUuid||!merged.has(state.selectedQuestionUuid)){if(state.activeTab==="entry"){const ef=[...merged.values()].filter(e=>stageOf(e)!=="COMPLETED").sort((a,b)=>(b.updatedAt||0)-(a.updatedAt||0))[0];state.selectedQuestionUuid=ef?ef.questionUuid:""}else{const f=[...merged.values()].sort((a,b)=>(b.updatedAt||0)-(a.updatedAt||0))[0];state.selectedQuestionUuid=f?f.questionUuid:""}}saveWorkspace();renderAll();log(`已同步题目: ${rows.length} 条`)}
async function createByShot(imageBase64){if(!state.token||!state.username)throw new Error("请先登录后再使用截图录题");if(!imageBase64)throw new Error("截图数据为空");const c=await api("/api/questions","POST",{});const e=createEntry(c.data);state.entries.set(e.questionUuid,e);state.selectedQuestionUuid=e.questionUuid;state.stageFilter="PENDING_STEM";saveWorkspace();renderAll();const id=await submitOcrForEntry(e,imageBase64,"QUESTION_STEM");log(`截图录题已创建任务并提交OCR: ${e.questionUuid} / ${id}`)}
async function triggerScreenshot(intent){state.screenshotIntent=intent;const shortcut=intent==="insert-image"?(state.config.imageScreenshotShortcut||state.config.screenshotShortcut):state.config.screenshotShortcut;await window.qforge.screenshot.trigger({intent,shortcut,triggerSource:"ui-button"})}
