$("bank-stem-save").addEventListener("click",async()=>{const e=bankSelectedEntry();if(!e)return;const blocks=collectBankBlocksFromEditor();const hasContent=blocks.some(b=>(b.type==="p"&&b.text.trim())||b.type!=="p");if(!hasContent){log("题干不能为空");return}const text=blocksToXml(blocks);try{await bankSaveStem(e.questionUuid,text);$("bank-stem-editor").classList.add("hidden");$("bank-stem-display").classList.remove("hidden");$("bank-edit-stem-btn").classList.remove("hidden")}catch(err){log(`保存题干失败: ${errMsg(err)}`)}});
$("bank-stem-structured-editor").addEventListener("input",ev=>{if(ev.target.matches(".block-text-input,.choice-text-input,.answer-area-lines-input"))bankEditorChanged()});
$("bank-stem-structured-editor").addEventListener("click",ev=>{const rmb=ev.target.closest(".block-remove-btn");if(rmb){const bl=rmb.closest(".stem-block");if(bl){bl.remove();bankEditorChanged()}return}if(ev.target.closest(".choice-image-shot-btn")){const e=bankSelectedEntry();if(!e){log("请先选择题目");return}const row=ev.target.closest(".choice-edit-row");const block=ev.target.closest(".stem-block");const blockIndex=[...$("bank-stem-structured-editor").querySelectorAll(".stem-block")].indexOf(block);pendingChoiceImageTarget={scope:"bank",questionUuid:e.questionUuid,blockIndex,choiceKey:row?.querySelector(".choice-text-input")?.dataset.key||""};triggerScreenshot("insert-image").catch(err=>log(`截图插图失败: ${err.message}`));return}if(ev.target.closest(".choice-image-clear-btn")){const row=ev.target.closest(".choice-edit-row");const preview=row?.querySelector(".choice-image-preview");if(preview){preview.dataset.ref="";preview.innerHTML="";bankEditorChanged()}return}if(ev.target.closest(".add-choice-item-btn")){const cb=ev.target.closest(".stem-choices-block");if(cb){const rows=cb.querySelectorAll(".choice-edit-row");const nk=String.fromCharCode(65+rows.length);const ct=cb.querySelector(".choices-items");const rw=document.createElement("div");rw.className="choice-edit-row";const ks=document.createElement("span");ks.className="choice-key-edit";ks.textContent=nk+".";const inp=document.createElement("input");inp.type="text";inp.className="choice-text-input";inp.dataset.key=nk;inp.placeholder="选项 "+nk+" 内容";const shot=document.createElement("button");shot.type="button";shot.className="btn btn-mini choice-image-shot-btn";shot.dataset.key=nk;shot.title="Ctrl+Alt+1 顺序插图";shot.textContent="截图插图";const clear=document.createElement("button");clear.type="button";clear.className="btn btn-mini btn-ghost choice-image-clear-btn";clear.dataset.key=nk;clear.textContent="清图";const preview=document.createElement("span");preview.className="choice-image-preview";preview.dataset.key=nk;preview.dataset.ref="";rw.appendChild(ks);rw.appendChild(inp);rw.appendChild(shot);rw.appendChild(clear);const delNw=document.createElement("button");delNw.type="button";delNw.className="btn btn-mini btn-danger choice-delete-btn";delNw.title="删除此选项";delNw.textContent="✖";rw.appendChild(delNw);rw.appendChild(preview);ct.appendChild(rw);bankEditorChanged()}return}if(ev.target.closest(".choice-delete-btn")){const row=ev.target.closest(".choice-edit-row");if(!row)return;const ct=row.parentElement;row.remove();if(ct){let ki=0;ct.querySelectorAll(".choice-edit-row").forEach(r=>{const key=String.fromCharCode(65+ki);const lbl=r.querySelector(".choice-key-edit");const inp=r.querySelector(".choice-text-input");const sbt=r.querySelector(".choice-image-shot-btn");const clr=r.querySelector(".choice-image-clear-btn");const prv=r.querySelector(".choice-image-preview");if(lbl)lbl.textContent=key+".";if(inp){inp.dataset.key=key;inp.placeholder="选项 "+key+" 内容"}if(sbt)sbt.dataset.key=key;if(clr)clr.dataset.key=key;if(prv)prv.dataset.key=key;ki++})}bankEditorChanged();return}if(ev.target.closest(".add-blank-item-btn")){const bb=ev.target.closest(".stem-blanks-block");if(bb){const chips=bb.querySelectorAll(".blank-edit-chip");const ni=chips.length+1;const ch=document.createElement("span");ch.className="blank-edit-chip";ch.textContent="\u7a7a"+ni;bb.querySelector(".blanks-edit-items").insertBefore(ch,ev.target.closest(".add-blank-item-btn"));bankEditorChanged()}return}});
$("bank-add-paragraph-btn").addEventListener("click",()=>addBankStemBlock("p"));
$("bank-add-choices-btn").addEventListener("click",()=>addBankStemBlock("choices"));
$("bank-add-blanks-btn").addEventListener("click",()=>addBankStemBlock("blanks"));
